sys_script_client.script:
function onChange(control, oldValue, newValue, isLoading, isTemplate) {

    if (isLoading || newValue == '') {
        return;
    }

    var requestType = g_form.getDisplayBox('request_type').value;

    if (requestType == 'VPN Access') {

        g_form.setValue('priority', 'Medium');

    }
    else if (requestType == 'Firewall Access') {

        g_form.setValue('priority', 'High');

    }
    else if (requestType == 'Static IP Allocation') {

        g_form.setValue('priority', 'Medium');

    }
    else if (requestType == 'Network Port Activation') {

        g_form.setValue('priority', 'Low');

    }

}
